78	    /// Create the STT service and preload the model from `model_path`.
79	    ///
80	    /// This function spawns a long-lived `std::thread` and returns immediately.
81	    pub fn new(
82	        model_path: impl AsRef<Path>,
83	        initial_prompt: Option<String>,
84	        shutdown: CancellationToken,
85	    ) -> Result<Self> {
86	        let model_path = model_path.as_ref().to_path_buf();
87	        ensure_model_exists(&model_path)?;
88	
89	        // Bounded queue: must not allow unbounded growth (T-02-07).
90	        let (job_tx, job_rx) = crossbeam_channel::bounded::<SttMsg>(4);
91	        let (result_tx, result_rx) = crossbeam_channel::bounded::<SttResult>(8);
92	
93	        Ok(Self {
94	            model_path,
95	            initial_prompt,
96	            job_tx,
97	            job_rx,
98	            result_tx,
99	            result_rx,
100	            shutdown,
101	            handle: None,
102	        })
103	    }
104	
105	    pub fn spawn(mut self) -> Result<Self> {
106	        let job_rx = self.job_rx.clone();
107	        let result_tx = self.result_tx.clone();
108	        let result_rx_for_drop = self.result_rx.clone();
109	        let shutdown = self.shutdown.clone();
110	
111	        let model_path = self.model_path.clone();
112	        let initial_prompt = self.initial_prompt.clone();
113	
114	        let handle = std::thread::spawn(move || {
115	            tracing::info!("STT thread started");
116	
117	            #[cfg(not(feature = "stt"))]
118	            {
119	                let _ = (model_path, initial_prompt); // silence unused warnings
120	                let _ = (&job_rx, &result_tx, &result_rx_for_drop, &shutdown);
121	                tracing::error!("STT is enabled but binary was built without `--features stt`");
122	                tracing::info!("STT thread stopped");
123	            }
124	
125	            #[cfg(feature = "stt")]
126	            {
127	                use whisper_rs::{
128	                    FullParams, SamplingStrategy, WhisperContext, WhisperContextParameters,
129	                };
130	                use std::time::Instant;
131	
132	                // Load model once at startup (D-15).
133	                let start_load = Instant::now();
134	                let ctx = match WhisperContext::new_with_params(
135	                    model_path.to_string_lossy().to_string(),
136	                    WhisperContextParameters::default(),
137	                ) {
138	                    Ok(c) => c,
139	                    Err(e) => {
140	                        tracing::error!("Failed to load whisper model: {e}");
141	                        return;
142	                    }
143	                };
144	                tracing::info!("Whisper model loaded in {}ms", start_load.elapsed().as_millis());
145	
146	                let base_params = FullParams::new(SamplingStrategy::Greedy { best_of: 1 });
147	
148	                // Create state once and reuse across jobs — avoids heap fragmentation from
149	                // repeated 190 MB alloc/free cycles that cause bad_alloc after ~N utterances.
150	                let mut state = match ctx.create_state() {
151	                    Ok(s) => s,
152	                    Err(e) => {
153	                        tracing::error!("Failed to create whisper state: {e}");
154	                        return;
155	                    }
156	                };
157	
158	                loop {
159	                    if shutdown.is_cancelled() {
160	                        break;
161	                    }
162	
163	                    match job_rx.recv_timeout(Duration::from_millis(50)) {
164	                        Ok(SttMsg::Shutdown) => break,
165	                        Ok(SttMsg::Job(job)) => {
166	                            let stt_start = Instant::now();
167	
168	                            let mut params = base_params.clone();
169	                            params.set_print_special(false);
170	                            params.set_print_progress(false);
171	                            params.set_print_realtime(false);
172	                            params.set_print_timestamps(false);
173	                            params.set_translate(false);
174	                            if let Some(ref prompt) = initial_prompt {
175	                                params.set_initial_prompt(prompt);
176	                            }
177	
178	                            if let Err(e) = state.full(params, &job.audio) {
179	                                tracing::warn!(utterance_id = job.utterance_id, "whisper full() failed: {e}");
180	                                continue;
181	                            }
182	
183	                            let n = state.full_n_segments();
184	
185	                            let mut text = String::new();
186	                            for i in 0..n {
187	                                if let Some(seg) = state.get_segment(i) {
188	                                    let seg = seg
189	                                        .to_str_lossy()
190	                                        .unwrap_or_default();
191	                                    let seg = seg.trim();
192	                                    if !seg.is_empty() {
193	                                        text.push_str(seg);
194	                                        if !text.ends_with(' ') {
195	                                            text.push(' ');
196	                                        }
197	                                    }
198	                                }
199	                            }
200	                            let text = text.trim().to_string();
201	
202	                            let stt_ms = stt_start.elapsed().as_millis() as u64;
203	                            let audio_ms = ((job.audio.len() as u64) * 1000) / (crate::vad::SAMPLE_RATE_HZ as u64);
204	
205	                            let mut timings = job.timings;
206	                            timings.mark_stt_done();
207	
208	                            let result = SttResult {
209	                                utterance_id: job.utterance_id,
210	                                text,
211	                                audio_ms,
212	                                stt_ms,
213	                                timings,
214	                                start_frame_idx: job.start_frame_idx,
215	                                end_frame_idx: job.end_frame_idx,
216	                            };
217	
218	                            // Non-blocking bounded send with drop-oldest behavior.
219	                            if try_send_drop_oldest(&result_tx, &result_rx_for_drop, result).is_err() {
220	                                break;
221	                            }
222	                        }
223	                        Err(crossbeam_channel::RecvTimeoutError::Timeout) => continue,
224	                        Err(crossbeam_channel::RecvTimeoutError::Disconnected) => break,
225	                    }
226	                }
227	
228	                tracing::info!("STT thread stopped");
229	            }
230	        });
231	
232	        self.handle = Some(handle);
233	        Ok(self)
234	    }
