240	    pub fn join_best_effort(&mut self, timeout: Duration) {
241	        if let Some(handle) = self.handle.take() {
242	            let joiner = std::thread::spawn(move || handle.join());
243	            std::thread::sleep(timeout);
244	            drop(joiner);
245	        }
246	    }
247	}
